parameters.functionCode:
// Segment subscribers based on criteria
const items = $input.all();
const segments = {
  new_leads: [],
  engaged: [],
  inactive: []
};

for (const item of items) {
  const data = item.json;
  const daysSinceSignup = Math.floor((Date.now() - new Date(data.signup_date).getTime()) / (1000 * 60 * 60 * 24));
  const lastEngagement = data.last_engagement_days || 999;

  if (daysSinceSignup <= 7) {
    segments.new_leads.push(item);
  } else if (lastEngagement <= 30) {
    segments.engaged.push(item);
  } else {
    segments.inactive.push(item);
  }
}

return [
  { json: { segment: 'new_leads', subscribers: segments.new_leads } },
  { json: { segment: 'engaged', subscribers: segments.engaged } },
  { json: { segment: 'inactive', subscribers: segments.inactive } }
];

// Welcome email template for new leads
const subscribers = $json.subscribers;
const emails = [];

for (const sub of subscribers) {
  const data = sub.json;
  emails.push({
    email: data.email,
    name: data.name || 'Valued Customer',
    subject: '🎉 Welcome! Get Started with {{company_name}}',
    template: 'welcome',
    personalization: {
      first_name: data.name?.split(' ')[0] || 'there',
      company_name: '{{company_name}}',
      special_offer: '20% off your first purchase',
      cta_link: '{{website_url}}/welcome-offer'
    }
  });
}

return emails.map(email => ({ json: email }));

// Engagement email template
const subscribers = $json.subscribers;
const emails = [];

for (const sub of subscribers) {
  const data = sub.json;
  emails.push({
    email: data.email,
    name: data.name || 'Valued Customer',
    subject: '✨ New Features & Tips Just for You',
    template: 'engagement',
    personalization: {
      first_name: data.name?.split(' ')[0] || 'there',
      company_name: '{{company_name}}',
      content_highlights: 'Latest blog posts, case studies, and product updates',
      cta_link: '{{website_url}}/resources'
    }
  });
}

return emails.map(email => ({ json: email }));

// Re-engagement email template
const subscribers = $json.subscribers;
const emails = [];

for (const sub of subscribers) {
  const data = sub.json;
  emails.push({
    email: data.email,
    name: data.name || 'Valued Customer',
    subject: '💌 We Miss You! Exclusive Comeback Offer Inside',
    template: 'reengagement',
    personalization: {
      first_name: data.name?.split(' ')[0] || 'there',
      company_name: '{{company_name}}',
      special_offer: '30% off to welcome you back',
      cta_link: '{{website_url}}/comeback-offer'
    }
  });
}

return emails.map(email => ({ json: email }));

// Generate campaign summary
const items = $input.all();
const summary = {
  total_sent: items.length,
  by_segment: {},
  timestamp: new Date().toISOString(),
  success_rate: '100%'
};

for (const item of items) {
  const segment = item.json.template || 'unknown';
  summary.by_segment[segment] = (summary.by_segment[segment] || 0) + 1;
}

return [{ json: summary }];

